namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string CategorySlug { get; set; } = "";
    public string Ingredients { get; set; } = "";
    public string Steps { get; set; } = "";
    public string ImagePlaceholder { get; set; } = "🍽️";
    public int TotalRating { get; set; }
    public int RatingCount { get; set; }
    public double AverageRating => RatingCount > 0 ? (double)TotalRating / RatingCount : 0;
}

public class Category
{
    public string Name { get; set; } = "";
    public string Slug { get; set; } = "";
    public string Icon { get; set; } = "";
    public string Description { get; set; } = "";
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Category> _categories;
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _categories = new List<Category>
        {
            new() { Name = "Breakfast", Slug = "breakfast", Icon = "🥞", Description = "Start your day right with these morning favorites." },
            new() { Name = "Main Courses", Slug = "main-courses", Icon = "🥩", Description = "Hearty dishes for lunch and dinner." },
            new() { Name = "Desserts", Slug = "desserts", Icon = "🍰", Description = "Sweet treats to finish any meal." },
            new() { Name = "Soups & Salads", Slug = "soups-salads", Icon = "🥗", Description = "Light and fresh options for any occasion." },
            new() { Name = "Snacks", Slug = "snacks", Icon = "🍿", Description = "Quick bites and appetizers." },
        };

        _recipes = new List<Recipe>
        {
            new()
            {
                Id = 1, Title = "Classic Pancakes", Category = "Breakfast", CategorySlug = "breakfast",
                ImagePlaceholder = "🥞", TotalRating = 18, RatingCount = 4,
                Ingredients = "2 cups flour\n2 eggs\n1½ cups milk\n2 tbsp sugar\n2 tsp baking powder\n½ tsp salt\n2 tbsp melted butter",
                Steps = "1. Mix dry ingredients in a large bowl.\n2. Whisk eggs, milk, and melted butter together.\n3. Combine wet and dry ingredients until just mixed.\n4. Heat a griddle over medium heat and grease lightly.\n5. Pour ¼ cup batter per pancake.\n6. Cook until bubbles form, then flip and cook until golden."
            },
            new()
            {
                Id = 2, Title = "Avocado Toast", Category = "Breakfast", CategorySlug = "breakfast",
                ImagePlaceholder = "🥑", TotalRating = 12, RatingCount = 3,
                Ingredients = "2 slices sourdough bread\n1 ripe avocado\n1 tbsp lemon juice\nSalt and pepper\nRed pepper flakes\n2 eggs (optional)",
                Steps = "1. Toast the bread until golden and crisp.\n2. Mash the avocado with lemon juice, salt, and pepper.\n3. Spread avocado mixture on toast.\n4. Top with red pepper flakes.\n5. Optionally, add a poached or fried egg on top."
            },
            new()
            {
                Id = 3, Title = "Spaghetti Bolognese", Category = "Main Courses", CategorySlug = "main-courses",
                ImagePlaceholder = "🍝", TotalRating = 25, RatingCount = 5,
                Ingredients = "1 lb ground beef\n1 onion, diced\n3 cloves garlic, minced\n1 can crushed tomatoes\n2 tbsp tomato paste\n1 tsp dried oregano\n1 tsp dried basil\n1 lb spaghetti\nSalt and pepper\nParmesan cheese",
                Steps = "1. Cook spaghetti according to package directions.\n2. Brown ground beef in a large skillet, drain fat.\n3. Add onion and garlic, cook until softened.\n4. Stir in crushed tomatoes, tomato paste, and herbs.\n5. Simmer for 20 minutes, stirring occasionally.\n6. Season with salt and pepper.\n7. Serve sauce over spaghetti with Parmesan."
            },
            new()
            {
                Id = 4, Title = "Grilled Chicken", Category = "Main Courses", CategorySlug = "main-courses",
                ImagePlaceholder = "🍗", TotalRating = 16, RatingCount = 4,
                Ingredients = "4 chicken breasts\n2 tbsp olive oil\n1 lemon, juiced\n2 cloves garlic, minced\n1 tsp paprika\n1 tsp dried thyme\nSalt and pepper",
                Steps = "1. Mix olive oil, lemon juice, garlic, paprika, thyme, salt, and pepper.\n2. Marinate chicken for at least 30 minutes.\n3. Preheat grill to medium-high heat.\n4. Grill chicken 6-7 minutes per side until internal temp reaches 165°F.\n5. Let rest 5 minutes before serving."
            },
            new()
            {
                Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
                ImagePlaceholder = "🍫", TotalRating = 20, RatingCount = 4,
                Ingredients = "4 oz dark chocolate\n½ cup butter\n1 cup powdered sugar\n2 eggs\n2 egg yolks\n6 tbsp flour\nButter and cocoa for ramekins",
                Steps = "1. Preheat oven to 425°F.\n2. Melt chocolate and butter together.\n3. Stir in powdered sugar until smooth.\n4. Whisk in eggs and egg yolks.\n5. Fold in flour.\n6. Grease ramekins with butter and dust with cocoa.\n7. Pour batter into ramekins.\n8. Bake 12-14 minutes until edges are firm but center is soft.\n9. Invert onto plates and serve immediately."
            },
            new()
            {
                Id = 6, Title = "Tomato Basil Soup", Category = "Soups & Salads", CategorySlug = "soups-salads",
                ImagePlaceholder = "🍅", TotalRating = 14, RatingCount = 3,
                Ingredients = "2 cans whole tomatoes\n1 onion, diced\n3 cloves garlic\n1 cup fresh basil\n1 cup heavy cream\n2 tbsp olive oil\nSalt and pepper",
                Steps = "1. Heat olive oil in a large pot.\n2. Sauté onion and garlic until soft.\n3. Add tomatoes and simmer 20 minutes.\n4. Blend until smooth with an immersion blender.\n5. Stir in cream and basil.\n6. Season with salt and pepper.\n7. Serve with crusty bread."
            },
            new()
            {
                Id = 7, Title = "Guacamole", Category = "Snacks", CategorySlug = "snacks",
                ImagePlaceholder = "🥑", TotalRating = 10, RatingCount = 2,
                Ingredients = "3 ripe avocados\n1 lime, juiced\n½ tsp salt\n½ cup diced onion\n3 tbsp chopped cilantro\n2 diced roma tomatoes\n1 tsp minced garlic\n1 pinch cayenne pepper",
                Steps = "1. Cut avocados in half, remove pit, scoop into bowl.\n2. Mash with a fork to desired consistency.\n3. Mix in lime juice and salt.\n4. Fold in onion, cilantro, tomatoes, and garlic.\n5. Add cayenne pepper.\n6. Refrigerate 1 hour for best flavor.\n7. Serve with tortilla chips."
            },
        };

        _nextId = 8;
    }

    public List<Category> GetCategories() => _categories;

    public Category? GetCategory(string slug) =>
        _categories.FirstOrDefault(c => c.Slug == slug);

    public List<Recipe> GetRecipesByCategory(string categorySlug) =>
        _recipes.Where(r => r.CategorySlug == categorySlug).ToList();

    public Recipe? GetRecipe(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipe(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRating += stars;
            recipe.RatingCount++;
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var cat = _categories.FirstOrDefault(c => c.Slug == category) ?? _categories[0];
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = cat.Name,
            CategorySlug = cat.Slug,
            Ingredients = ingredients,
            Steps = steps,
            ImagePlaceholder = cat.Icon
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

@page "/categories/{Slug}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(_category?.Name ?? "Category") — RecipeShare</PageTitle>

@if (_category is null)
{
    <h2>Category not found</h2>
    <p><a href="/">Back to Home</a></p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@_category.Name</li>
        </ol>
    </nav>

    <h1>@_category.Icon @_category.Name</h1>
    <p class="lead">@_category.Description</p>

    @if (_recipes.Count == 0)
    {
        <div class="alert alert-info">No recipes in this category yet. <a href="submit">Be the first to submit one!</a></div>
    }
    else
    {
        <div class="row row-cols-1 row-cols-md-2 g-4">
            @foreach (var recipe in _recipes)
            {
                <div class="col">
                    <a href="recipe/@recipe.Id" class="text-decoration-none">
                        <div class="card h-100 shadow-sm">
                            <div class="card-body">
                                <div class="d-flex align-items-center mb-2">
                                    <span style="font-size: 2rem;" class="me-2">@recipe.ImagePlaceholder</span>
                                    <h5 class="card-title mb-0">@recipe.Title</h5>
                                </div>
                                <p class="card-text text-muted mb-1">
                                    @if (recipe.RatingCount > 0)
                                    {
                                        <span>@RenderStars(recipe.AverageRating) (@recipe.RatingCount ratings)</span>
                                    }
                                    else
                                    {
                                        <span>No ratings yet</span>
                                    }
                                </p>
                            </div>
                        </div>
                    </a>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string Slug { get; set; } = "";

    private Category? _category;
    private List<Recipe> _recipes = new();

    protected override void OnParametersSet()
    {
        _category = RecipeService.GetCategory(Slug);
        _recipes = _category is not null ? RecipeService.GetRecipesByCategory(Slug) : new();
    }

    private static string RenderStars(double rating)
    {
        var full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (_recipe is null)
{
    <h2>Recipe not found</h2>
    <p><a href="/">Back to Home</a></p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="categories/@_recipe.CategorySlug">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <div class="d-flex align-items-center mb-3">
        <span style="font-size: 3rem;" class="me-3">@_recipe.ImagePlaceholder</span>
        <div>
            <h1 class="mb-0">@_recipe.Title</h1>
            <span class="badge bg-primary">@_recipe.Category</span>
        </div>
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><strong>🧾 Ingredients</strong></div>
                <div class="card-body">
                    <ul class="list-unstyled mb-0">
                        @foreach (var line in _recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <li class="mb-1">• @line</li>
                        }
                    </ul>
                </div>
            </div>
        </div>

        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><strong>📋 Steps</strong></div>
                <div class="card-body">
                    @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p class="mb-2">@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="card">
        <div class="card-body">
            <h5>⭐ Rate This Recipe</h5>
            <StarRating RecipeId="_recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipe(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>📝 Submit a Recipe</h1>
<p class="lead">Share your favorite recipe with the community.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@_title</strong>" has been added.</p>
        <a href="recipe/@_newRecipeId" class="btn btn-primary me-2">View Recipe</a>
        <button class="btn btn-outline-secondary" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" @bind-Value="_title" class="form-control" placeholder="e.g., Grandma's Apple Pie" required />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" @bind-Value="_categorySlug" class="form-select">
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat.Slug">@cat.Icon @cat.Name</option>
                        }
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" @bind-Value="_ingredients" class="form-control" rows="6"
                                   placeholder="One ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" required />
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Preparation Steps</label>
                    <InputTextArea id="steps" @bind-Value="_steps" class="form-control" rows="8"
                                   placeholder="Describe each step&#10;e.g.,&#10;1. Preheat oven to 350°F.&#10;2. Mix dry ingredients.&#10;3. Add wet ingredients." required />
                </div>

                <button type="submit" class="btn btn-success btn-lg"
                        disabled="@(string.IsNullOrWhiteSpace(_title) || string.IsNullOrWhiteSpace(_ingredients) || string.IsNullOrWhiteSpace(_steps))">
                    Submit Recipe
                </button>
            </div>

            <div class="col-md-4">
                <div class="card bg-light">
                    <div class="card-body">
                        <h5 class="card-title">💡 Tips</h5>
                        <ul class="small">
                            <li>List one ingredient per line</li>
                            <li>Number your steps for clarity</li>
                            <li>Include cooking times and temperatures</li>
                            <li>Mention serving size if relevant</li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    </EditForm>
}

@code {
    private string _title = "";
    private string _categorySlug = "breakfast";
    private string _ingredients = "";
    private string _steps = "";
    private bool _submitted;
    private int _newRecipeId;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_title)) return;
        var recipe = RecipeService.AddRecipe(_title, _categorySlug, _ingredients, _steps);
        _newRecipeId = recipe.Id;
        _submitted = true;
    }

    private void ResetForm()
    {
        _title = "";
        _categorySlug = "breakfast";
        _ingredients = "";
        _steps = "";
        _submitted = false;
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="d-flex align-items-center gap-3">
    <div class="star-rating" style="font-size: 1.8rem; cursor: pointer; user-select: none;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="@(star <= (_hovered > 0 ? _hovered : _selected) ? "text-warning" : "text-muted")"
                  @onclick="() => SelectStar(star)"
                  @onmouseover="() => _hovered = star"
                  @onmouseout="() => _hovered = 0"
                  role="button"
                  title="@star star(s)">★</span>
        }
    </div>

    @if (_selected > 0)
    {
        <span class="text-success fw-bold">Thanks! You rated @_selected star(s).</span>
    }
    else
    {
        <span class="text-muted">Click a star to rate</span>
    }

    @if (_recipe is not null && _recipe.RatingCount > 0)
    {
        <span class="text-muted small">
            Avg: @_recipe.AverageRating.ToString("F1") / 5 (@_recipe.RatingCount ratings)
        </span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    private int _selected;
    private int _hovered;
    private Models.Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipe(RecipeId);
    }

    private void SelectStar(int star)
    {
        if (_selected > 0) return; // only allow one rating
        _selected = star;
        RecipeService.AddRating(RecipeId, star);
        _recipe = RecipeService.GetRecipe(RecipeId);
    }
}

