using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Category> _categories;
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _categories = new List<Category>
        {
            new() { Name = "Breakfast", Slug = "breakfast", Icon = "🥞", Description = "Start your day right with these morning favorites." },
            new() { Name = "Main Courses", Slug = "main-courses", Icon = "🥩", Description = "Hearty dishes for lunch and dinner." },
            new() { Name = "Desserts", Slug = "desserts", Icon = "🍰", Description = "Sweet treats to finish any meal." },
            new() { Name = "Soups & Salads", Slug = "soups-salads", Icon = "🥗", Description = "Light and fresh options for any occasion." },
            new() { Name = "Snacks", Slug = "snacks", Icon = "🍿", Description = "Quick bites and appetizers." },
        };

        _recipes = new List<Recipe>
        {
            new()
            {
                Id = 1, Title = "Classic Pancakes", Category = "Breakfast", CategorySlug = "breakfast",
                ImagePlaceholder = "🥞", TotalRating = 18, RatingCount = 4,
                Ingredients = "2 cups flour\n2 eggs\n1½ cups milk\n2 tbsp sugar\n2 tsp baking powder\n½ tsp salt\n2 tbsp melted butter",
                Steps = "1. Mix dry ingredients in a large bowl.\n2. Whisk eggs, milk, and melted butter together.\n3. Combine wet and dry ingredients until just mixed.\n4. Heat a griddle over medium heat and grease lightly.\n5. Pour ¼ cup batter per pancake.\n6. Cook until bubbles form, then flip and cook until golden."
            },
            new()
            {
                Id = 2, Title = "Avocado Toast", Category = "Breakfast", CategorySlug = "breakfast",
                ImagePlaceholder = "🥑", TotalRating = 12, RatingCount = 3,
                Ingredients = "2 slices sourdough bread\n1 ripe avocado\n1 tbsp lemon juice\nSalt and pepper\nRed pepper flakes\n2 eggs (optional)",
                Steps = "1. Toast the bread until golden and crisp.\n2. Mash the avocado with lemon juice, salt, and pepper.\n3. Spread avocado mixture on toast.\n4. Top with red pepper flakes.\n5. Optionally, add a poached or fried egg on top."
            },
            new()
            {
                Id = 3, Title = "Spaghetti Bolognese", Category = "Main Courses", CategorySlug = "main-courses",
                ImagePlaceholder = "🍝", TotalRating = 25, RatingCount = 5,
                Ingredients = "1 lb ground beef\n1 onion, diced\n3 cloves garlic, minced\n1 can crushed tomatoes\n2 tbsp tomato paste\n1 tsp dried oregano\n1 tsp dried basil\n1 lb spaghetti\nSalt and pepper\nParmesan cheese",
                Steps = "1. Cook spaghetti according to package directions.\n2. Brown ground beef in a large skillet, drain fat.\n3. Add onion and garlic, cook until softened.\n4. Stir in crushed tomatoes, tomato paste, and herbs.\n5. Simmer for 20 minutes, stirring occasionally.\n6. Season with salt and pepper.\n7. Serve sauce over spaghetti with Parmesan."
            },
            new()
            {
                Id = 4, Title = "Grilled Chicken", Category = "Main Courses", CategorySlug = "main-courses",
                ImagePlaceholder = "🍗", TotalRating = 16, RatingCount = 4,
                Ingredients = "4 chicken breasts\n2 tbsp olive oil\n1 lemon, juiced\n2 cloves garlic, minced\n1 tsp paprika\n1 tsp dried thyme\nSalt and pepper",
                Steps = "1. Mix olive oil, lemon juice, garlic, paprika, thyme, salt, and pepper.\n2. Marinate chicken for at least 30 minutes.\n3. Preheat grill to medium-high heat.\n4. Grill chicken 6-7 minutes per side until internal temp reaches 165°F.\n5. Let rest 5 minutes before serving."
            },
            new()
            {
                Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
                ImagePlaceholder = "🍫", TotalRating = 20, RatingCount = 4,
                Ingredients = "4 oz dark chocolate\n½ cup butter\n1 cup powdered sugar\n2 eggs\n2 egg yolks\n6 tbsp flour\nButter and cocoa for ramekins",
                Steps = "1. Preheat oven to 425°F.\n2. Melt chocolate and butter together.\n3. Stir in powdered sugar until smooth.\n4. Whisk in eggs and egg yolks.\n5. Fold in flour.\n6. Grease ramekins with butter and dust with cocoa.\n7. Pour batter into ramekins.\n8. Bake 12-14 minutes until edges are firm but center is soft.\n9. Invert onto plates and serve immediately."
            },
            new()
            {
                Id = 6, Title = "Tomato Basil Soup", Category = "Soups & Salads", CategorySlug = "soups-salads",
                ImagePlaceholder = "🍅", TotalRating = 14, RatingCount = 3,
                Ingredients = "2 cans whole tomatoes\n1 onion, diced\n3 cloves garlic\n1 cup fresh basil\n1 cup heavy cream\n2 tbsp olive oil\nSalt and pepper",
                Steps = "1. Heat olive oil in a large pot.\n2. Sauté onion and garlic until soft.\n3. Add tomatoes and simmer 20 minutes.\n4. Blend until smooth with an immersion blender.\n5. Stir in cream and basil.\n6. Season with salt and pepper.\n7. Serve with crusty bread."
            },
            new()
            {
                Id = 7, Title = "Guacamole", Category = "Snacks", CategorySlug = "snacks",
                ImagePlaceholder = "🥑", TotalRating = 10, RatingCount = 2,
                Ingredients = "3 ripe avocados\n1 lime, juiced\n½ tsp salt\n½ cup diced onion\n3 tbsp chopped cilantro\n2 diced roma tomatoes\n1 tsp minced garlic\n1 pinch cayenne pepper",
                Steps = "1. Cut avocados in half, remove pit, scoop into bowl.\n2. Mash with a fork to desired consistency.\n3. Mix in lime juice and salt.\n4. Fold in onion, cilantro, tomatoes, and garlic.\n5. Add cayenne pepper.\n6. Refrigerate 1 hour for best flavor.\n7. Serve with tortilla chips."
            },
        };

        _nextId = 8;
    }

    public List<Category> GetCategories() => _categories;

    public Category? GetCategory(string slug) =>
        _categories.FirstOrDefault(c => c.Slug == slug);

    public List<Recipe> GetRecipesByCategory(string categorySlug) =>
        _recipes.Where(r => r.CategorySlug == categorySlug).ToList();

    public Recipe? GetRecipe(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipe(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRating += stars;
            recipe.RatingCount++;
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var cat = _categories.FirstOrDefault(c => c.Slug == category) ?? _categories[0];
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = cat.Name,
            CategorySlug = cat.Slug,
            Ingredients = ingredients,
            Steps = steps,
            ImagePlaceholder = cat.Icon
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

