@page "/categories/{Slug}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(_category?.Name ?? "Category") — RecipeShare</PageTitle>

@if (_category is null)
{
    <h2>Category not found</h2>
    <p><a href="/">Back to Home</a></p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@_category.Name</li>
        </ol>
    </nav>

    <h1>@_category.Icon @_category.Name</h1>
    <p class="lead">@_category.Description</p>

    @if (_recipes.Count == 0)
    {
        <div class="alert alert-info">No recipes in this category yet. <a href="submit">Be the first to submit one!</a></div>
    }
    else
    {
        <div class="row row-cols-1 row-cols-md-2 g-4">
            @foreach (var recipe in _recipes)
            {
                <div class="col">
                    <a href="recipe/@recipe.Id" class="text-decoration-none">
                        <div class="card h-100 shadow-sm">
                            <div class="card-body">
                                <div class="d-flex align-items-center mb-2">
                                    <span style="font-size: 2rem;" class="me-2">@recipe.ImagePlaceholder</span>
                                    <h5 class="card-title mb-0">@recipe.Title</h5>
                                </div>
                                <p class="card-text text-muted mb-1">
                                    @if (recipe.RatingCount > 0)
                                    {
                                        <span>@RenderStars(recipe.AverageRating) (@recipe.RatingCount ratings)</span>
                                    }
                                    else
                                    {
                                        <span>No ratings yet</span>
                                    }
                                </p>
                            </div>
                        </div>
                    </a>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string Slug { get; set; } = "";

    private Category? _category;
    private List<Recipe> _recipes = new();

    protected override void OnParametersSet()
    {
        _category = RecipeService.GetCategory(Slug);
        _recipes = _category is not null ? RecipeService.GetRecipesByCategory(Slug) : new();
    }

    private static string RenderStars(double rating)
    {
        var full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

