@page "/recipe/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (_recipe is null)
{
    <h2>Recipe not found</h2>
    <p><a href="/">Back to Home</a></p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="categories/@_recipe.CategorySlug">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <div class="d-flex align-items-center mb-3">
        <span style="font-size: 3rem;" class="me-3">@_recipe.ImagePlaceholder</span>
        <div>
            <h1 class="mb-0">@_recipe.Title</h1>
            <span class="badge bg-primary">@_recipe.Category</span>
        </div>
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><strong>🧾 Ingredients</strong></div>
                <div class="card-body">
                    <ul class="list-unstyled mb-0">
                        @foreach (var line in _recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <li class="mb-1">• @line</li>
                        }
                    </ul>
                </div>
            </div>
        </div>

        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><strong>📋 Steps</strong></div>
                <div class="card-body">
                    @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p class="mb-2">@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="card">
        <div class="card-body">
            <h5>⭐ Rate This Recipe</h5>
            <StarRating RecipeId="_recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipe(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>📝 Submit a Recipe</h1>
<p class="lead">Share your favorite recipe with the community.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@_title</strong>" has been added.</p>
        <a href="recipe/@_newRecipeId" class="btn btn-primary me-2">View Recipe</a>
        <button class="btn btn-outline-secondary" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" @bind-Value="_title" class="form-control" placeholder="e.g., Grandma's Apple Pie" required />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" @bind-Value="_categorySlug" class="form-select">
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat.Slug">@cat.Icon @cat.Name</option>
                        }
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" @bind-Value="_ingredients" class="form-control" rows="6"
                                   placeholder="One ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" required />
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Preparation Steps</label>
                    <InputTextArea id="steps" @bind-Value="_steps" class="form-control" rows="8"
                                   placeholder="Describe each step&#10;e.g.,&#10;1. Preheat oven to 350°F.&#10;2. Mix dry ingredients.&#10;3. Add wet ingredients." required />
                </div>

                <button type="submit" class="btn btn-success btn-lg"
                        disabled="@(string.IsNullOrWhiteSpace(_title) || string.IsNullOrWhiteSpace(_ingredients) || string.IsNullOrWhiteSpace(_steps))">
                    Submit Recipe
                </button>
            </div>

            <div class="col-md-4">
                <div class="card bg-light">
                    <div class="card-body">
                        <h5 class="card-title">💡 Tips</h5>
                        <ul class="small">
                            <li>List one ingredient per line</li>
                            <li>Number your steps for clarity</li>
                            <li>Include cooking times and temperatures</li>
                            <li>Mention serving size if relevant</li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    </EditForm>
}

@code {
    private string _title = "";
    private string _categorySlug = "breakfast";
    private string _ingredients = "";
    private string _steps = "";
    private bool _submitted;
    private int _newRecipeId;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_title)) return;
        var recipe = RecipeService.AddRecipe(_title, _categorySlug, _ingredients, _steps);
        _newRecipeId = recipe.Id;
        _submitted = true;
    }

    private void ResetForm()
    {
        _title = "";
        _categorySlug = "breakfast";
        _ingredients = "";
        _steps = "";
        _submitted = false;
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="d-flex align-items-center gap-3">
    <div class="star-rating" style="font-size: 1.8rem; cursor: pointer; user-select: none;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="@(star <= (_hovered > 0 ? _hovered : _selected) ? "text-warning" : "text-muted")"
                  @onclick="() => SelectStar(star)"
                  @onmouseover="() => _hovered = star"
                  @onmouseout="() => _hovered = 0"
                  role="button"
                  title="@star star(s)">★</span>
        }
    </div>

    @if (_selected > 0)
    {
        <span class="text-success fw-bold">Thanks! You rated @_selected star(s).</span>
    }
    else
    {
        <span class="text-muted">Click a star to rate</span>
    }

    @if (_recipe is not null && _recipe.RatingCount > 0)
    {
        <span class="text-muted small">
            Avg: @_recipe.AverageRating.ToString("F1") / 5 (@_recipe.RatingCount ratings)
        </span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    private int _selected;
    private int _hovered;
    private Models.Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipe(RecipeId);
    }

    private void SelectStar(int star)
    {
        if (_selected > 0) return; // only allow one rating
        _selected = star;
        RecipeService.AddRating(RecipeId, star);
        _recipe = RecipeService.GetRecipe(RecipeId);
    }
}

